sql:
SELECT name
FROM swimmers
WHERE swimmer_id IN (SELECT swimmer_id FROM swimmer_events);

SELECT DISTINCT s.name
FROM swimmers s
JOIN swimmer_events se ON s.swimmer_id = se.swimmer_id;

SELECT name, nationality
FROM swimmers
ORDER BY name ASC;

external_knowledge:
'swimmers with the fastest average pace times' implies ranking swimmers by their average pace time in ascending order; 
'past five years' is determined by the date('now', '-5 years') function; 
'top 5 swimmers' refers to the first five swimmers in the ranking.

